css:
.loader {
  position: relative;
  width: 60px;
  height: 60px;
  background: #a19dad;
  transform: rotateX(65deg) rotate(45deg);
  color: #ffffff;
  animation: layerStack 1s linear infinite alternate;
}
.loader::after {
  content: "";
  position: absolute;
  inset: 0;
  background: rgba(255,255,255,.7);
  animation: layerTravel 1s linear infinite alternate;
}
@keyframes layerStack { 0% { box-shadow: 0 0 0 0; } 90%,100% { box-shadow: 20px 20px 0 -4px; } }
@keyframes layerTravel { 0% { transform: translate(0,0) scale(1); } 100% { transform: translate(-25px,-25px) scale(1); } }
